const run_id = `BUPA_SYNC_${Date.now()}_${Math.random().toString(36).substring(2, 8)}`;

return [{
  json: {
    sync_scope: 'all_active',
    dry_run: false,
    run_id: run_id
  }
}];

const employeeData = $('Read Active Employees').first().json;
const vendorData = $('Read Employee Vendors').first().json;
const params = $('Set Parameters').first().json;

// Mock S/4 returns { count, results: [...] }
const employees = employeeData.results || employeeData.data || (Array.isArray(employeeData) ? employeeData : []);
const vendors = vendorData.results || vendorData.data || (Array.isArray(vendorData) ? vendorData : []);

// Extract PERNRs from both sources
const employeePernrs = employees.map(e => e.PERNR || e.pernr || '');
const vendorPernrs = vendors.map(v => v.PERNR || v.pernr || '');

// Combine and deduplicate
const allPernrs = [...new Set([...employeePernrs, ...vendorPernrs].filter(Boolean))];

console.log(`[M1 Milestone] Population identified: ${allPernrs.length} unique employees`);

return [{
  json: {
    total_employees: allPernrs.length,
    employee_list: allPernrs,
    run_id: params.run_id,
    milestone: 'M1',
    milestone_message: `Population count complete: ${allPernrs.length} employees in scope`
  }
}];

const status = $('Check Job Status').first().json;
const params = $('Merge and Count Population').first().json;

console.log(`[M2 Milestone] Sync job completed. Status: ${status.status || 'completed'}`);

return [{
  json: {
    ...status,
    run_id: params.run_id,
    total_employees: params.total_employees,
    milestone: 'M2',
    milestone_message: `Sync execution complete. Job status: ${status.status || 'completed'}`
  }
}];

const syncData = $('Read Sync Error Log').first().json;
const slg1Data = $('Read SLG1 Log').first().json;
const context = $('M2 Milestone Log').first().json;

// Mock S/4 returns { count, results } or plain array
const syncErrors = syncData.results || syncData.data || (Array.isArray(syncData) ? syncData : []);
const slg1Errors = slg1Data.results || slg1Data.data || (Array.isArray(slg1Data) ? slg1Data : []);

// Normalize sync errors
const normalizedSync = syncErrors.map(e => ({
  employee_id: e.PERNR || e.pernr || e.employee_id || '',
  error_class: e.error_class || e.MSG_CLASS || 'SYNC_ERROR',
  error_message: e.error_message || e.MESSAGE || e.msg || '',
  error_source: 'BUPA_SYNC',
  timestamp: e.timestamp || new Date().toISOString(),
  related_bp_id: e.BP_ID || e.bp_id || e.related_bp_id || ''
}));

// Normalize SLG1 errors
const normalizedSlg1 = slg1Errors.map(e => ({
  employee_id: e.PERNR || e.pernr || e.employee_id || '',
  error_class: e.error_class || e.MSGID || 'SLG1_ERROR',
  error_message: e.error_message || e.MSGTEXT || e.msg || '',
  error_source: 'SLG1',
  timestamp: e.timestamp || e.DATUM || new Date().toISOString(),
  related_bp_id: e.BP_ID || e.bp_id || e.related_bp_id || ''
}));

// Combine and deduplicate by employee_id + error_message
const allErrors = [...normalizedSync, ...normalizedSlg1];
const seen = new Set();
const deduped = allErrors.filter(e => {
  const key = `${e.employee_id}|${e.error_message}`;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

console.log(`[M3 Milestone] Error consolidation: ${deduped.length} unique errors`);

return [{
  json: {
    errors: deduped,
    error_count: deduped.length,
    run_id: context.run_id,
    total_employees: context.total_employees,
    milestone: 'M3',
    milestone_message: `Error merge complete: ${deduped.length} unique errors identified`
  }
}];

const agentResponse = $('Invoke BUPA Sync Agent').first().json;
const context = $('Merge Errors').first().json;

// Extract content from agent response
let responseContent = '';
if (agentResponse.choices && agentResponse.choices[0]) {
  responseContent = agentResponse.choices[0].message?.content || '';
} else if (agentResponse.content) {
  responseContent = agentResponse.content;
} else if (agentResponse.response) {
  responseContent = typeof agentResponse.response === 'string' ? agentResponse.response : JSON.stringify(agentResponse.response);
} else {
  responseContent = JSON.stringify(agentResponse);
}

// Try to parse fix proposals from the response
let fixProposals = [];
try {
  // Look for JSON in the response
  const jsonMatch = responseContent.match(/\[[\s\S]*?\]/)
    || responseContent.match(/\{[\s\S]*"fixes"[\s\S]*\}/);
  if (jsonMatch) {
    const parsed = JSON.parse(jsonMatch[0]);
    fixProposals = Array.isArray(parsed) ? parsed : (parsed.fixes || []);
  }
} catch (e) {
  // If JSON parsing fails, create a single proposal from the text
  fixProposals = [{
    description: responseContent.substring(0, 500),
    confidence_score: 0.6,
    category: 'general'
  }];
}

// Categorize by confidence
const high = fixProposals.filter(f => (f.confidence_score || 0) > 0.8);
const medium = fixProposals.filter(f => (f.confidence_score || 0) >= 0.5 && (f.confidence_score || 0) <= 0.8);
const low = fixProposals.filter(f => (f.confidence_score || 0) < 0.5);

console.log(`[M4 Milestone] Agent analysis complete: ${fixProposals.length} fix proposals (${high.length} high, ${medium.length} medium, ${low.length} low confidence)`);

return [{
  json: {
    fix_proposals: fixProposals,
    high_confidence: high,
    medium_confidence: medium,
    low_confidence: low,
    agent_raw_response: responseContent,
    errors: context.errors,
    error_count: context.error_count,
    run_id: context.run_id,
    total_employees: context.total_employees,
    milestone: 'M4',
    milestone_message: `Agent analysis complete: ${fixProposals.length} proposals generated`
  }
}];

// This path is taken when there are no errors
const context = $('Merge Errors').first().json;

return [{
  json: {
    fix_proposals: [],
    high_confidence: [],
    medium_confidence: [],
    low_confidence: [],
    agent_raw_response: 'No errors detected - agent not invoked',
    errors: [],
    error_count: 0,
    run_id: context.run_id,
    total_employees: context.total_employees,
    milestone: 'M4',
    milestone_message: 'No errors found - skipping agent analysis'
  }
}];

// Gather data from whichever path was taken
let data;
try {
  data = $('Parse Agent Response').first().json;
} catch (e) {
  data = $('No Errors - Skip Agent').first().json;
}

const now = new Date().toISOString();
const errorsByCategory = {};
(data.errors || []).forEach(e => {
  const cat = e.error_class || 'UNKNOWN';
  errorsByCategory[cat] = (errorsByCategory[cat] || 0) + 1;
});

const successCount = data.total_employees - data.error_count;
const coveragePct = data.total_employees > 0
  ? ((successCount / data.total_employees) * 100).toFixed(1)
  : '100.0';

const report = [
  '═══════════════════════════════════════════════════════════════',
  '           BUPA SYNC RECONCILIATION REPORT',
  '═══════════════════════════════════════════════════════════════',
  '',
  `Run ID:          ${data.run_id}`,
  `Timestamp:       ${now}`,
  '',
  '─── POPULATION ────────────────────────────────────────────────',
  `Total Employees in Scope:  ${data.total_employees}`,
  `Successfully Synced:       ${successCount}`,
  `Errors Encountered:        ${data.error_count}`,
  `Coverage:                  ${coveragePct}%`,
  '',
  '─── ERROR BREAKDOWN ───────────────────────────────────────────',
  ...Object.entries(errorsByCategory).map(([cat, count]) => `  ${cat}: ${count}`),
  data.error_count === 0 ? '  No errors detected.' : '',
  '',
  '─── FIX PROPOSALS ─────────────────────────────────────────────',
  `Total Proposals:       ${(data.fix_proposals || []).length}`,
  `High Confidence:       ${(data.high_confidence || []).length}`,
  `Medium Confidence:     ${(data.medium_confidence || []).length}`,
  `Low Confidence:        ${(data.low_confidence || []).length}`,
  '',
  ...(data.fix_proposals || []).slice(0, 10).map((p, i) =>
    `  [${i + 1}] (score: ${(p.confidence_score || 0).toFixed(2)}) ${p.description || p.fix || 'N/A'}`
  ),
  '',
  '─── SUMMARY ───────────────────────────────────────────────────',
  `Status: ${data.error_count === 0 ? 'SUCCESS - All employees synced' : 'ATTENTION REQUIRED - Errors detected'}`,
  '',
  '═══════════════════════════════════════════════════════════════',
].join('\n');

return [{
  json: {
    report: report,
    run_id: data.run_id,
    total_employees: data.total_employees,
    error_count: data.error_count,
    coverage_pct: parseFloat(coveragePct),
    fix_proposals_count: (data.fix_proposals || []).length
  }
}];

const report = $('Generate Reconciliation Report').first().json;

console.log(`[M5 Milestone] Workflow complete. Run: ${report.run_id}, Coverage: ${report.coverage_pct}%, Errors: ${report.error_count}, Fixes proposed: ${report.fix_proposals_count}`);
console.log('\n' + report.report);

return [{
  json: {
    ...report,
    milestone: 'M5',
    milestone_message: 'BUPA Sync workflow completed successfully',
    completed_at: new Date().toISOString()
  }
}];
